PowerShell.Script:
$paths = @(
    'C:\Drivers'
    'C:\Windows\Temp\*'
    'C:\Windows\SystemTemp\*'
    'C:\Windows\Downloaded Installations\*'
    'C:\Windows\*.log'
    'C:\Windows\Logs\CBS\*'
    'C:\Windows\Logs\DISM\*'
    'C:\Windows\Panther\*'
    'C:\Users\Public\Desktop\*'
)

foreach ($path in $paths) {
    Write-Host "Deleting $path" -NoNewLine
    if (Test-Path $path) {
        Remove-Item $path -Recurse -Force -ErrorAction SilentlyContinue
        Write-Host " - Success"
    } else {
        Write-Host " - Not found, skipping"
    }
}

$regBase = 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\VolumeCaches'
$categories = @( 'Active Setup Temp Folders' 'BranchCache' 'Downloaded Program Files' 'GameNewsFiles' 'GameStatisticsFiles' 'GameUpdateFiles' 'Internet Cache Files' 'Memory Dump Files' 'Offline Pages Files' 'Old ChkDsk Files' # 'Previous Installations' 'Recycle Bin' # 'Service Pack Cleanup' 'Setup Log Files' 'System error memory dump files' 'System error minidump files' 'Temporary Files' 'Temporary Setup Files' 'Temporary Sync Files' 'Thumbnail Cache' # 'Update Cleanup' 'Upgrade Discarded Files' 'User file versions' 'Windows Defender' 'Windows Error Reporting Archive Files' 'Windows Error Reporting Queue Files' 'Windows Error Reporting System Archive Files' 'Windows Error Reporting System Queue Files' # 'Windows ESD installation files' 'Windows Upgrade Log Files' )
foreach ($category in $categories) { $path = "$regBase\$category" if (Test-Path $path) { Set-ItemProperty -Path $path -Name 'StateFlags0100' -Value 2 -Type DWord } }
$cleanmgr = "$env:SystemRoot\System32\cleanmgr.exe" if (Test-Path $cleanmgr) { Write-Host "Running Disk Cleanup for all categories..." Start-Process $cleanmgr -ArgumentList '/sagerun:100' -Wait Write-Host "Disk Cleanup completed." }

[Array]$EventLogs = & wevtutil enum-logs
$EventLogs += "System"
Write-Host 'Clear event logs'
# Clear all event log entries
foreach ($EventLog in $EventLogs) {
    Write-Host "Clearing $EventLog" -NoNewline
    & wevtutil cl "$EventLog" 2> $null
    if ($?) {
        Write-Host " - Success"
    } else {
        Write-Host " - Failed"
    }
}

Write-Host "NGEN running"
if ($(Test-Path $Env:WinDir\Microsoft.Net\Framework64\v4.0.30319\ngen.exe) -eq $True) {
    . $Env:WinDir\Microsoft.Net\Framework64\v4.0.30319\ngen.exe Update
    Write-Host "Done"
} else {
    Write-Host "Skipped, no x64"
}

$ghostNICs = Get-CimInstance Win32_NetworkAdapter | Where-Object { $_.Installed -eq $true -and $null -eq $_.MACAddress -and $_.Description -iin @( # Intel (emulated, used by many hypervisors) 'Intel(R) PRO/1000 MT Network Connection' 'Intel(R) PRO/1000 MT Desktop Adapter' 'Intel(R) PRO/1000 PF Server Adapter' 'Intel(R) 82574L Gigabit Network Connection' 'Intel 21140-Based PCI Fast Ethernet Adapter (Emulated)' # AMD/PCNet (VMware legacy, Xen) 'AMD PCNET Family PCI Ethernet Adapter' 'Lance/PCI Ethernet Adapter' 'Realtek RTL8139C+ Fast Ethernet NIC' # VMware 'VMware VMXNET2 Ethernet Adapter' 'VMware Accelerated AMD PCNet Adapter' 'vmxnet3 Ethernet Adapter' # Citrix XenServer / Xen 'Citrix PV Ethernet Adapter' 'Citrix PV Network Adapter' 'Xen Net Device Driver' # Microsoft Hyper-V 'Microsoft Virtual Machine Bus Network Adapter' 'Microsoft Hyper-V Network Adapter' # Nutanix AHV (VirtIO) 'Red Hat VirtIO Ethernet Adapter' 'VIRTIO Ethernet Adapter' ) }
if (-not $ghostNICs) { Write-Host 'No Ghost NICs found.' -ForegroundColor Yellow exit 0 }
foreach ($nic in $ghostNICs) { $nicProps = Get-ItemProperty -Path ("HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4D36E972-E325-11CE-BFC1-08002BE10318}\{0:D4}" -f [int]$nic.DeviceID) -ErrorAction SilentlyContinue $netProps = Get-ItemProperty -Path ("HKLM:\SYSTEM\CurrentControlSet\Control\Network\{4D36E972-E325-11CE-BFC1-08002BE10318}\$($nicProps.NetCfgInstanceId)\Connection") -ErrorAction SilentlyContinue
Write-Host "" Write-Host -NoNewline "ID : "; Write-Host ("{0:D4}" -f [int]$nic.DeviceID) Write-Host -NoNewline "Network: "; Write-Host $netProps.Name Write-Host -NoNewline "NIC : "; Write-Host $nic.Name Write-Host -NoNewline "Actions: Removing... "
$result = & pnputil /remove-device "@$($nicProps.DeviceInstanceID)" 2>&1 if ($LASTEXITCODE -eq 0) { Write-Host 'Success!' } else { Write-Host "Error [$LASTEXITCODE]" } }

$regBase = 'HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces\'

$dhcpProperties = @(
    'DhcpDefaultGateway'
    'DhcpIPAddress'
    'DhcpNameServer'
    'DhcpServer'
    'DhcpSubnetMask'
    'DhcpSubnetMaskOpt'
)

if (Test-Path $regBase) {
    Get-ChildItem $regBase -ErrorAction SilentlyContinue | ForEach-Object {
        Write-Host "Processing: $($_.Name)"
        $keyPath = $_.PSPath
        $key = Get-ItemProperty -Path $keyPath
        foreach ($property in $dhcpProperties) {
            if ($null -ne $key.$property) {
                Set-ItemProperty -Path $keyPath -Name $property -Value '' -ErrorAction SilentlyContinue
                Write-Host "Cleared: $($_.PSChildName)\$property"
            }
        }
    }
}
